16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.ObjectMapper;
19	import io.micronaut.http.HttpResponse;
20	import io.micronaut.http.annotation.Controller;
21	import io.micronaut.http.annotation.Get;
22	import io.micronaut.http.annotation.PathVariable;
23	import io.micronaut.http.annotation.QueryValue;
24	import io.micronaut.scheduling.TaskExecutors;
25	import io.micronaut.scheduling.annotation.ExecuteOn;
26	import jakarta.inject.Inject;
27	import java.io.BufferedReader;
28	import java.io.IOException;
29	import java.nio.file.Files;
30	import java.nio.file.Path;
31	import java.nio.file.Paths;
32	import java.util.HashMap;
33	import java.util.List;
34	import java.util.Map;
35	import java.util.Optional;
36	import java.util.stream.Collectors;
37	import java.util.stream.Stream;
38	
39	@Controller("/api/brain")
40	public class BrainController {
41	
42	    private final List<SessionSource> sessionSources;
43	
44	    @Inject
45	    public BrainController(List<SessionSource> sessionSources) {
46	        this.sessionSources = sessionSources;
47	    }
48	
49	    private Optional<SessionSource> sourceFor(String flavor) {
50	        return sessionSources.stream().filter(s -> s.handles(flavor)).findFirst();
51	    }
52	
53	    @ExecuteOn(TaskExecutors.IO)
54	    @Get("/conversations")
55	    public List<Map<String, String>> listConversations(@QueryValue Optional<String> flavor) {
56	        Optional<SessionSource> source = sourceFor(flavor.orElse(""));
57	        if (source.isPresent()) {
58	            return source.get().listConversations();
59	        }
60	        Path brainPath = AntigravityPaths.brainDir(flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR));
61	        if (!Files.exists(brainPath)) return List.of();
62	
63	        try (Stream<Path> paths = Files.list(brainPath)) {
64	            return paths
65	                .filter(p -> {
66	                    if (!Files.isDirectory(p)) return false;
67	                    Path transcriptPath = AntigravityPaths.transcript(AntigravityPaths.logsDir(p));
68	                    if (!Files.exists(transcriptPath)) return false;
69	                    try {
70	                        return Files.size(transcriptPath) > 0;
71	                    } catch (IOException e) {
72	                        return false;
73	                    }
74	                })
75	                .map(p -> {
76	                    String id = p.getFileName().toString();
77	                    Map<String, String> info = new HashMap<>();
78	                    info.put("id", id);
79	
80	                    Path logs = AntigravityPaths.logsDir(p);
81	                    String summary = "Conversation " + id.substring(0, 8);
82	                    Path shortTitlePath = AntigravityPaths.shortTitle(logs);
83	                    if (Files.exists(shortTitlePath)) {
84	                        try {
85	                            summary = Files.readString(shortTitlePath).trim();
86	                        } catch (IOException e) {}
87	                    } else {
88	                        Path transcriptPath = AntigravityPaths.transcript(logs);
89	                        if (Files.exists(transcriptPath)) {
90	                            try (BufferedReader reader = Files.newBufferedReader(transcriptPath)) {
91	                                ObjectMapper mapper = new ObjectMapper();
92	                                String line;
93	                                while ((line = reader.readLine()) != null) {
94	                                    if (line.contains("\"USER_INPUT\"")) {
95	                                        Map<String, Object> map = mapper.readValue(line, Map.class);
96	                                        if ("USER_INPUT".equals(map.get("type"))) {
97	                                            String content = (String) map.getOrDefault(
98	                                                "content",
99	                                                ""
100	                                            );
101	                                            content =
102	                                                content.replaceAll("(?s)<USER_REQUEST>\\s*", "");
103	                                            int endIdx = content.indexOf("</USER_REQUEST>");
104	                                            if (endIdx != -1) {
105	                                                content = content.substring(0, endIdx);
106	                                            }
107	                                            content = content.trim();
108	                                            if (content.length() > 80) {
109	                                                content = content.substring(0, 80) + "...";
110	                                            }
111	                                            if (!content.isEmpty()) {
112	                                                summary = content;
113	                                            }
114	                                            break;
115	                                        }
116	                                    }
117	                                }
118	                            } catch (Exception e) {}
119	                        }
120	                    }
121	
122	                    info.put("summary", summary);
123	                    try {
124	                        Path transcriptPath = AntigravityPaths.transcript(logs);
125	                        long modified = Files.getLastModifiedTime(transcriptPath).toMillis();
126	                        info.put("updatedAt", String.valueOf(modified));
127	                    } catch (IOException e) {
128	                        info.put("updatedAt", "0");
129	                    }
130	                    return info;
131	                })
132	                .sorted((a, b) ->
133	                    Long.compare(
134	                        Long.parseLong(b.get("updatedAt")),
135	                        Long.parseLong(a.get("updatedAt"))
136	                    )
137	                )
138	                .collect(Collectors.toList());
139	        } catch (IOException e) {
140	            e.printStackTrace();
141	            return List.of();
142	        }
143	    }
144	
145	    @ExecuteOn(TaskExecutors.IO)
146	    @Get(value = "/conversations/{id}/transcript", produces = "application/json")
147	    public String getTranscript(@PathVariable String id, @QueryValue Optional<String> flavor)
148	        throws IOException {
149	        Optional<SessionSource> source = sourceFor(flavor.orElse(""));
150	        if (source.isPresent()) {
151	            return source.get().transcriptJson(id);
152	        }
153	        Path logs = AntigravityPaths.logsDir(flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR), id);
154	        Path transcriptPath = AntigravityPaths.transcriptFull(logs);
155	        if (!Files.exists(transcriptPath)) {
156	            transcriptPath = AntigravityPaths.transcript(logs);
157	        }
158	        if (!Files.exists(transcriptPath)) {
159	            return "[]";
160	        }
161	
162	        // Read JSONL and convert to a JSON array of objects
163	        try (Stream<String> lines = Files.lines(transcriptPath)) {
164	            String jsonArray = lines
165	                .map(String::trim)
166	                .filter(line -> !line.isEmpty())
167	                .collect(Collectors.joining(",", "[", "]"));
168	            return jsonArray;
169	        }
170	    }
171	
172	    @ExecuteOn(TaskExecutors.IO)
173	    @Get(value = "/file", produces = "text/plain")
174	    public HttpResponse<String> getFileContent(@QueryValue String path) {
175	        try {
176	            Path filePath = Paths.get(path).normalize();
177	            Path geminiDir = AntigravityPaths.geminiRoot().normalize();
178	            if (!filePath.startsWith(geminiDir)) {
179	                return HttpResponse.unauthorized();
180	            }
181	            if (Files.exists(filePath) && !Files.isDirectory(filePath)) {
182	                return HttpResponse.ok(Files.readString(filePath));
183	            } else {
184	                return HttpResponse.notFound("File not found or is a directory.");
185	            }
186	        } catch (IOException e) {
187	            return HttpResponse.serverError("Error reading file: " + e.getMessage());
188	        }
189	    }
190	}
