21	/**
22	 * The single source of truth for Antigravity's on-disk layout under the user's home. Antigravity
23	 * stores each flavor's sessions in {@code ~/.gemini/<flavor>/brain/<id>/.system_generated/logs/},
24	 * and the previous scattering of these literals across the brain controller, analysis controller,
25	 * and session collector was the duplication this consolidates.
26	 *
27	 * <p>{@code user.home} is read on every call (not cached) so tests that redirect it are honoured.
28	 */
29	final class AntigravityPaths {
30	
31	    private AntigravityPaths() {}
32	
33	    /** The flavor used when none is supplied. */
34	    static final String DEFAULT_FLAVOR = "antigravity-cli";
35	
36	    private static final String LOGS_DIR = ".system_generated";
37	    private static final String LOGS_SUBDIR = "logs";
38	    private static final String TRANSCRIPT = "transcript.jsonl";
39	    private static final String TRANSCRIPT_FULL = "transcript_full.jsonl";
40	    private static final String SUMMARY_JSON = "summary.json";
41	    private static final String SHORT_TITLE = "short_title.txt";
42	
43	    /** The {@code ~/.gemini} root (used both for brain lookups and file-access sandboxing). */
44	    static Path geminiRoot() {
45	        return Paths.get(System.getProperty("user.home"), ".gemini");
46	    }
47	
48	    /** The {@code brain} directory for a flavor; a null/blank flavor falls back to the default. */
49	    static Path brainDir(String flavor) {
50	        String dir = (flavor == null || flavor.isEmpty()) ? DEFAULT_FLAVOR : flavor;
51	        return geminiRoot().resolve(dir).resolve("brain");
52	    }
53	
54	    /** The generated-logs directory inside a given session directory. */
55	    static Path logsDir(Path sessionDir) {
56	        return sessionDir.resolve(LOGS_DIR).resolve(LOGS_SUBDIR);
57	    }
58	
59	    /** The generated-logs directory for a session id under a flavor's brain. */
60	    static Path logsDir(String flavor, String id) {
61	        return logsDir(brainDir(flavor).resolve(id));
62	    }
63	
64	    static Path transcript(Path logsDir) {
65	        return logsDir.resolve(TRANSCRIPT);
66	    }
67	
68	    static Path transcriptFull(Path logsDir) {
69	        return logsDir.resolve(TRANSCRIPT_FULL);
70	    }
71	
72	    static Path summaryJson(Path logsDir) {
73	        return logsDir.resolve(SUMMARY_JSON);
74	    }
75	
76	    static Path shortTitle(Path logsDir) {
77	        return logsDir.resolve(SHORT_TITLE);
78	    }
