18	import io.micronaut.runtime.Micronaut;
19	import java.util.Locale;
20	import java.util.Map;
21	
22	public class Application {
23	
24	    public static void main(String[] args) {
25	        for (String arg : args) {
26	            if ("-h".equals(arg) || "--help".equals(arg)) {
27	                printHelp();
28	                System.exit(0);
29	            } else if ("-v".equals(arg) || "--version".equals(arg)) {
30	                System.out.println("Agent Brain Visualizer version " + Version.VERSION);
31	                System.exit(0);
32	            }
33	        }
34	        applyDotEnvFrameworkSettings();
35	        Micronaut.run(Application.class, args);
36	    }
37	
38	    /**
39	     * Feeds {@code MICRONAUT_*} entries from a {@code .env} file into system properties (e.g.
40	     * {@code MICRONAUT_SERVER_PORT} → {@code micronaut.server.port}) so the framework honours them.
41	     * Real environment variables and explicit {@code -D} flags take precedence over the file. The AI
42	     * settings are read separately by {@link AiConfig}.
43	     */
44	    private static void applyDotEnvFrameworkSettings() {
45	        applyFrameworkSettings(DotEnv.values());
46	    }
47	
48	    /** The pure half of {@link #applyDotEnvFrameworkSettings()}, so the precedence rules are testable. */
49	    static void applyFrameworkSettings(Map<String, String> values) {
50	        for (Map.Entry<String, String> entry : values.entrySet()) {
51	            String key = entry.getKey();
52	            String value = entry.getValue();
53	            if (!key.startsWith("MICRONAUT_")) continue;
54	            // A blank value would fail Micronaut's property resolution; ignore the line instead.
55	            if (value == null || value.isBlank()) continue;
56	            if (System.getenv(key) != null) continue; // a real environment variable wins
57	            String property = key.toLowerCase(Locale.ROOT).replace('_', '.');
58	            if (System.getProperty(property) == null) { // an explicit -D flag wins
59	                System.setProperty(property, value);
60	            }
61	        }
62	    }
63	
64	    private static void printHelp() {
65	        System.out.println("""
66	                Agent Brain Visualizer
67	                ======================
68	                A web interface for inspecting AI agent execution transcripts.
69	
70	                Usage:
71	                  cp .env.example .env    # then edit .env (or export the variables)
72	                  ./agy-brain-viz [options]
73	
74	                Configuration is read from real environment variables first, then from a `.env`
75	                file in the current directory (copy `.env.example` to get started).
76	
77	                Options:
78	                  -Dmicronaut.server.port=<port>   Run on a custom port (default: 8080)
79	                  -Ddotenv.enabled=false           Ignore any .env file
80	                  -Ddotenv.path=<path>             Load a .env file from a custom path
81	                  -h, --help                       Show this help message and exit
82	                  -v, --version                    Print the version information and exit
83	
84	                Environment Variables (or .env entries):
85	                  AI_PROVIDER                      `gemini` (default) or `ollama`
86	                  GEMINI_API_KEY                   Required to generate summaries with Gemini
87	                  GEMINI_MODEL                     Gemini model name
88	                  OLLAMA_BASE_URL, OLLAMA_MODEL    Local Ollama server and model
89	                  MICRONAUT_SERVER_PORT            Overrides the default server port
90	                """);
91	    }
