100	    /** Parses {@code KEY=VALUE} lines. See the class docs for the accepted format. */
101	    static Map<String, String> parse(List<String> lines) {
102	        Map<String, String> values = new LinkedHashMap<>();
103	        if (lines == null) return values;
104	        for (String raw : lines) {
105	            if (raw == null) continue;
106	            String line = raw.strip();
107	            // A UTF-8 BOM isn't whitespace, so it would otherwise become part of the first key.
108	            if (!line.isEmpty() && line.charAt(0) == '﻿') line = line.substring(1).strip();
109	            if (line.isEmpty() || line.startsWith("#")) continue;
110	            line = EXPORT_PREFIX.matcher(line).replaceFirst("");
111	
112	            int equals = line.indexOf('=');
113	            if (equals <= 0) continue; // no key, or no '=' at all
114	            String key = line.substring(0, equals).strip();
115	            if (key.isEmpty()) continue;
116	            values.put(key, cleanValue(line.substring(equals + 1).strip()));
117	        }
118	        return values;
