23	/**
24	 * Shared logic for turning normalized timeline steps (the schema produced by the per-source adapters
25	 * such as {@link CodexAdapter} and {@link ClaudeCodeAdapter}) into condensed LLM-analysis input: one
26	 * list of short lines per user-initiated sequence, mirroring
27	 * {@link TranscriptParser#parseSequences(List)}. User prompts, agent tool calls, and failed tool
28	 * outputs are summarized; successful outputs and reasoning are omitted. Assistant narration is
29	 * mostly omitted because its prose dominates verbose sessions, but the <em>final</em> assistant
30	 * message (the agent's outcome/conclusion) is always kept, plus a small budget of earlier assistant
31	 * messages — this preserves the stated outcome for the summary while keeping the token footprint
32	 * small.
33	 */
34	final class NormalizedSteps {
35	
36	    private NormalizedSteps() {}
37	
38	    // The final assistant message (outcome) is always included up to this length; earlier assistant
39	    // messages share a small total budget so verbose sessions don't blow up the analysis input.
40	    private static final int ASSISTANT_FINAL_MAX = 2000;
41	    private static final int ASSISTANT_OTHER_MAX_EACH = 500;
42	    private static final int ASSISTANT_OTHER_BUDGET = 2000;
43	
44	    static List<List<String>> toAnalysisSequences(List<ObjectNode> steps) {
45	        int lastMessageIndex = lastMessageIndex(steps);
46	        int assistantBudget = ASSISTANT_OTHER_BUDGET;
47	
48	        List<List<String>> sequences = new ArrayList<>();
49	        List<String> current = new ArrayList<>();
50	        for (int i = 0; i < steps.size(); i++) {
51	            ObjectNode step = steps.get(i);
52	            String type = step.path("type").asText("");
53	
54	            String line;
55	            if ("MESSAGE".equals(type)) {
56	                String content = step.path("content").asText("");
57	                if (content.isBlank()) continue;
58	                if (i == lastMessageIndex) {
59	                    line = "ASSISTANT: " + truncate(content, ASSISTANT_FINAL_MAX);
60	                } else if (assistantBudget > 0) {
61	                    String text = truncate(
62	                        content,
63	                        Math.min(ASSISTANT_OTHER_MAX_EACH, assistantBudget)
64	                    );
65	                    assistantBudget -= text.length();
66	                    line = "ASSISTANT: " + text;
67	                } else {
68	                    continue;
69	                }
70	            } else {
71	                line = analysisLine(step, type);
72	                if (line == null) continue;
73	            }
74	
75	            if ("USER_INPUT".equals(type) && !current.isEmpty()) {
76	                sequences.add(TranscriptParser.deduplicateSequence(current));
77	                current = new ArrayList<>();
78	            }
79	            current.add(line);
80	        }
81	        if (!current.isEmpty()) {
82	            sequences.add(TranscriptParser.deduplicateSequence(current));
83	        }
84	        return sequences;
85	    }
86	
87	    private static int lastMessageIndex(List<ObjectNode> steps) {
88	        int idx = -1;
89	        for (int i = 0; i < steps.size(); i++) {
90	            ObjectNode step = steps.get(i);
91	            if (
92	                "MESSAGE".equals(step.path("type").asText("")) &&
93	                !step.path("content").asText("").isBlank()
94	            ) {
95	                idx = i;
96	            }
97	        }
98	        return idx;
99	    }
100	
101	    private static String analysisLine(ObjectNode step, String type) {
102	        switch (type) {
103	            case "USER_INPUT":
104	                return "USER REQUEST: " + truncate(step.path("content").asText(""), 2000);
105	            case "FUNCTION_CALL":
106	                {
107	                    JsonNode tool = step.path("tool_calls").path(0);
108	                    String name = tool.path("name").asText("unknown");
109	                    return "AGENT ACTION: [" + name + "] " + argsSummary(tool.path("args"));
110	                }
111	            case "FUNCTION_OUTPUT":
112	                if ("ERROR".equals(step.path("status").asText(""))) {
113	                    return "SYSTEM EVENT/ERROR: " + truncate(step.path("content").asText(""), 500);
114	                }
115	                return null;
116	            default:
117	                return null;
118	        }
119	    }
120	
121	    private static String argsSummary(JsonNode args) {
122	        if (args == null || args.isMissingNode() || args.isNull()) return "";
123	        // Prefer a human-meaningful field across tools (Codex: cmd; Claude Code: command/file_path).
124	        for (String key : new String[] { "cmd", "command", "file_path" }) {
125	            JsonNode value = args.get(key);
126	            if (value != null && value.isTextual()) {
127	                return truncate(value.asText(), 200);
128	            }
129	        }
130	        return truncate(args.toString(), 200);
131	    }
132	
133	    private static String truncate(String text, int max) {
134	        if (text == null) return "";
135	        return text.length() > max ? text.substring(0, max) : text;
136	    }
137	}
